#include <SPI.h>
#include <Servo.h>
extern float complementary_filter(float,float,float,float,float);
extern int pid_heater_control(float,float,float,float,float,float,float*,float*);
float roll=0,pitch=0;
Servo esc[4];
void esc_setup(){
  int p[]={3,5,6,9};
  for(int i=0;i<4;i++){esc[i].attach(p[i]);esc[i].writeMicroseconds(1000);}
  delay(2000);}
void esc_write(int a,int b,int c,int d){
  esc[0].writeMicroseconds(a);esc[1].writeMicroseconds(b);
  esc[2].writeMicroseconds(c);esc[3].writeMicroseconds(d);}
void esc_disarm(){esc_write(1000,1000,1000,1000);}
bool imu_read(float* gr,float* gp,float* ar,float* ap){
  *gr=0;*gp=0;*ar=0;*ap=0;return true;}
volatile int ppm[4]={1500,1500,1500,1000};
void ppm_isr(){}
void ppm_setup(){attachInterrupt(digitalPinToInterrupt(4),ppm_isr,CHANGE);}
static float igR=0,leR=0,igP=0,leP=0;
void attitude_step(float dt){
  float gr,gp,ar,ap;
  if(!imu_read(&gr,&gp,&ar,&ap)){esc_disarm();Serial.println("FAULT:IMU");while(1);}
  roll=complementary_filter(roll,gr,ar,dt,0.98f);
  pitch=complementary_filter(pitch,gp,ap,dt,0.98f);
  if(fabsf(roll)>45.0f||fabsf(pitch)>45.0f){esc_disarm();Serial.println("FAULT:ATT");while(1);}
  float spR=(ppm[0]-1500)/500.0f*30.0f;
  float spP=(ppm[1]-1500)/500.0f*30.0f;
  int cr=pid_heater_control(spR,roll,dt,1.5f,0.05f,0.1f,&igR,&leR);
  int cp=pid_heater_control(spP,pitch,dt,1.5f,0.05f,0.1f,&igP,&leP);
  int thr=ppm[3];
  esc_write(constrain(thr+cr+cp,1000,2000),constrain(thr-cr+cp,1000,2000),
            constrain(thr+cr-cp,1000,2000),constrain(thr-cr-cp,1000,2000));}
unsigned long pt=0;
void setup(){Serial.begin(115200);esc_setup();ppm_setup();}
void loop(){
  unsigned long n=micros();
  float dt=(n-pt)/1e6f;
  if(dt<0.001f)return;
  pt=n;
  attitude_step(dt);
  if(millis()%100<2){Serial.print(roll);Serial.print(',');Serial.println(pitch);}}
